import React, { useMemo } from "react";

/**
 * WeatherOverlay
 * - Full-screen, behind content
 * - Non-blocking (pointer-events-none)
 * - Gradient fallback if an image fails
 * - Controllable zoom & fit
 *
 * Props:
 *   condition?: string   // e.g., "Rain", "Clear", "Clouds", "Thunder"
 *   timeOfDay?: "auto" | "day" | "night"
 *   zoom?: number        // 0.75–1.0 (default 0.85) -> smaller = “zoomed out”
 *   fit?: "cover" | "contain"  // how the image fits the screen (default "cover")
 *   position?: string    // background-position, e.g., "center", "top", "50% 60%" (default "center")
 */

// NOTE: adjust these import paths/filenames to EXACTLY match your project
import Sun from "./overlays/Sun-Weather-App.gif";
import Rain from "./overlays/Rain-Weather-App.gif";
import Snow from "./overlays/Snowy-Weather-App.gif";
import Wind from "./overlays/Windy-Weather-App.gif";
import Clouds from "./overlays/partly cloudy sky Gif.gif";
import Night from "./overlays/PCnight.gif";
import Day from "./overlays/PCday.gif";

function pickOverlay(condition = "", timeOfDay = "auto") {
  const c = (condition || "").toLowerCase();

  // time-based preference if provided
  if (timeOfDay === "night") return Night || Clouds;
  if (timeOfDay === "day") return Day || Sun;

  if (c.includes("thunder")) return Rain;
  if (c.includes("rain") || c.includes("drizzle") || c.includes("shower")) return Rain;
  if (c.includes("snow") || c.includes("sleet")) return Snow;
  if (c.includes("clear")) return Sun;
  if (c.includes("cloud")) return Clouds;
  if (c.includes("wind")) return Wind;

  return Clouds; // safe default
}

export default function WeatherOverlay({
  condition = "",
  timeOfDay = "auto",
  zoom = 0.85,          // smaller value = less “zoomed in”
  fit = "cover",        // "cover" or "contain"
  position = "center",  // background-position
}) {
  const src = useMemo(() => {
    try {
      return pickOverlay(condition, timeOfDay);
    } catch {
      return null;
    }
  }, [condition, timeOfDay]);

  // Clamp zoom to something reasonable
  const z = Math.max(0.6, Math.min(1.0, zoom || 0.85));

  return (
    <div className="absolute inset-0 -z-10 pointer-events-none">
      {/* Fallback gradient so you always see something */}
      <div className="absolute inset-0 bg-gradient-to-b from-violet-900/40 via-fuchsia-700/20 to-black" />

      {/* Background layer with controllable zoom/fit */}
      {src && (
        <div
          className="absolute inset-0"
          style={{
            backgroundImage: `url(${src})`,
            backgroundRepeat: "no-repeat",
            backgroundSize: fit === "contain" ? "contain" : "cover",
            backgroundPosition: position,
            transform: `scale(${z})`,        // zoom control
            transformOrigin: "center center",
          }}
          // If the image 404s, this layer just won't show; gradient remains
        />
      )}

      {/* Vignette for readability */}
      <div className="absolute inset-0 bg-black/20" />
    </div>
  );
}
